const ALLOWED_TAGS = new Set([
  "geo", "maps", "time-series", "charts", "comparison", "search", "education",
  "culture", "gallery", "fun", "media", "collections", "health", "alerts",
  "science", "finance", "trending", "social", "ranking", "transit",
  "real-time", "tools", "local",
]);

if (batch.length !== 180) {
  throw new Error(`Expected 180 entries, got ${batch.length}`);
}

const ids = new Set();
for (const item of batch) {
  if (ids.has(item.id)) throw new Error(`duplicate id: ${item.id}`);
  ids.add(item.id);
  if (item.sampleFields.length !== 3) throw new Error(`${item.id}: sampleFields must be length 3`);
  if (item.tags.length < 2 || item.tags.length > 4) throw new Error(`${item.id}: tags must be 2-4`);
  for (const tag of item.tags) {
    if (!ALLOWED_TAGS.has(tag)) throw new Error(`${item.id}: invalid tag ${tag}`);
  }
}

writeFileSync(outPath, JSON.stringify(batch, null, 2));
console.log(`Wrote ${batch.length} entries to ${outPath}`);
